<?php
declare(strict_types=1);require __DIR__.'/bootstrap.php';$base='http://localhost/Ferrocheck/public/index.php?modulo=control-escaneres&seccion=catalogo';function catalogGet(string$url):string{$context=stream_context_create(['http'=>['timeout'=>5,'ignore_errors'=>true]]);$html=file_get_contents($url,false,$context);if($html===false)throw new RuntimeException('GET local falló.');return$html;}
$partial=catalogGet($base.'&q=SC-900');test('GET parcial incluye ambos fixtures',fn()=>ok(str_contains($partial,'SC-9001')&&str_contains($partial,'SC-9002')));$exact=catalogGet($base.'&q=SC-9001');test('GET exacto incluye uno',fn()=>ok(str_contains($exact,'SC-9001')&&!str_contains($exact,'SC-9002')));$numeric=catalogGet($base.'&q=9001');test('GET fragmento numérico',fn()=>ok(str_contains($numeric,'SC-9001')));$lower=catalogGet($base.'&q=sc-900');test('GET minúsculas',fn()=>ok(str_contains($lower,'SC-9001')&&str_contains($lower,'SC-9002')));$spaces=catalogGet($base.'&q='.rawurlencode('  SC-900  '));test('GET recorta espacios',fn()=>ok(str_contains($spaces,'SC-9001')&&str_contains($spaces,'SC-9002')));$missing=catalogGet($base.'&q=NO-EXISTE');test('GET inexistente muestra vacío',fn()=>ok(!str_contains($missing,'SC-9001')&&str_contains($missing,'No encontramos')));$empty=catalogGet($base.'&q=');test('GET vacío no restringe',fn()=>ok(str_contains($empty,'SC-9001')&&str_contains($empty,'SC-9002')));$combined=catalogGet($base.'&q=SC-900&estado=disponible');test('GET combinado con estado',fn()=>ok(str_contains($combined,'SC-9001')&&!str_contains($combined,'SC-9002')));$page=catalogGet($base.'&q=SC-900&por_pagina=1&pagina=1');test('paginación conserva búsqueda',fn()=>ok(str_contains($page,'SC-900')&&str_contains($page,'q=SC-900')));finish('Catalog HTTP');
